-- Migration 039: Fen Bilimleri sinif 5-8 tam re-seed
-- Mevcut kısa kodlu (FB.x.y.z) kayıtları sil, doğru 5-parçalı kodlarla (FB.x.y.z.w) ekle
-- PDF: refs/mufredat-2025/2025825154137627-fen bilimleri.pdf
-- Toplam: 28+36+36+43 = 143 yeni kayıt

DO $$
DECLARE
  fb_id UUID;
BEGIN
  SELECT id INTO fb_id FROM branslar WHERE slug = 'fen_bilimleri';

  -- Mevcut sinif 5-8 kayıtlarını sil (kod format yanlıştı: FB.x.y.z)
  DELETE FROM kazanimlar WHERE brans_id = fb_id AND sinif IN (5, 6, 7, 8);

  -- Yeni kayıtları ekle (doğru 5-parçalı kod formatı: FB.x.y.z.w)

  RAISE NOTICE 'Fen Bilimleri sinif 5-8: % kayıt eklendi', 143;
END $$;