  (fb_id, 'FB.7.3.4.1', 7, 3, 'VÜCUDUMUZDAKİ SİSTEMLER', 'Boşaltım sistemini oluşturan yapı ve organları model üzerinde gözlemleyebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.3.4.2', 7, 3, 'VÜCUDUMUZDAKİ SİSTEMLER', 'Boşaltım sisteminin sağlığı için yapılması gerekenler konusunda bilgi toplayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.4.1.1', 7, 4, 'IŞIĞIN KIRILMASI VE MERCEKLER', 'Ortam değiştiren ışığın izlediği yolu gözlemleyerek kırılma olayına yönelik bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.4.2.1', 7, 4, 'IŞIĞIN KIRILMASI VE MERCEKLER', 'Mercek çeşitlerine yönelik bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.4.2.2', 7, 4, 'IŞIĞIN KIRILMASI VE MERCEKLER', 'Merceklerin günlük hayatta kullanım alanlarını örneklerle sınıflandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.1.1', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilere maddenin tanecikli yapıdan oluştuğu hatırlatılır. Öğrencilerden parkta oynadıkları sırada bir avuç kum alarak kumu diğer avucuna dökmeleri hayal ettirilebilir. Kum dökerken kum tanelerini fark etmeleri istenebilir. Park zemininin bu kum tanelerinin', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.1.2', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Atom kavramı ile ilgili bilginin ilk olarak ne zaman ortaya çıktığı ve Democritus''tan günümüze nasıl geliştiği öğrencilere belgeseller izletilerek merak uyandırılır. (E1.1). Öğrencilerin atom ile ilgili 5N1K tekniğine göre sorular sormaları istenir (E3.8, SDB2.1). Bu sorular tahtaya', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.1.3', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Maddelerin tanecikli yapısının molekül şeklinde de olabileceği, aynı veya farklı atomların belirli oranlarda bir araya gelerek molekülü oluşturabileceği belirtilir. Atomları modellemede oyun hamuru, pinpon topu vb. malzemeler kullanılarak (E2.5) öğrencilerin', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.1.4', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilere elektronların katmanlara dizilimi ile ilgili açık uçlu sorular sorulur. Dublet ve oktet kuralı orbital şemalarına girilmeden verilir. Öğrencilerin atomlarda elektronların dizilimindeki mantıksal ilişkileri ortaya koymaları beklenir. Periyodik tabloda yer alan ilk 18', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.2.1', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Tahtaya saf maddeleri temsil edebilecek çeşitli tanecikli yapı örnekleri çizilerek öğrencilerden bu örnekleri dikkatli bir şekilde incelemeleri istenir (OB4). Öğrencilerden saf maddelerin aynı veya farklı cins atomlardan meydana geldiğini fark etmeleri beklenir.', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.2.2', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Periyodik tablodaki ilk 18 elementin isimlerini sembolleriyle ifade edebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.2.3', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilere kitaplarını raflara yerleştirirken belirli ölçütleri dikkate alıp almadıkları ve düzen açısından belirli ölçütlerin olmasının nasıl bir fayda sağlayacağı sorulabilir (SDB2.1, E3.10). Öğrencilerin düşüncelerini özgürce ve kendine güvenerek ifade etmeleri ve', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.2.4', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilere farklı cins elementlerin bir araya gelerek bileşikleri oluşturabildiği hatırlatılır. Elementlerin sembollerle gösterilmesinden yola çıkılarak bileşiklerin nasıl gösterilebileceğine dair sorular yöneltilir (SDB2.1, SDB3.1, E3.4). Bileşiklerin de elementler', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.3.1', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilerin karışım kavramı ile ilgili ön öğrenmelerini açığa çıkarmak için açık uçlu sorular sorulabilir (SDB2.1, E1.1). Saf maddelerin özellikleri hatırlatılarak saf olmayan maddelerin özelliklerini nitelemeleri istenir (SDB3.1). Bileşiklerle karışımların birbirinden', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.3.2', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Çözünme hızına etki eden faktörler ile ilgili hipotez oluşturabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.5.4.1', 7, 5, 'MADDENİN DOĞASINA YOLCULUK', 'Öğrencilere günlük hayattan örnekler verilerek karışımların ayrılıp ayrılamayacağı ile ilgili açık uçlu sorular yöneltilebilir. Karışımları ayırmak için hangi fiziksel yöntemlerin kullanılabileceği ile ilgili beyin fırtınası tekniği yaptırılabilir (E3.4, SDB2.1). Karışımları', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.6.1.1', 7, 6, 'ELEKTRİKLENME', 'Elektriklenme ile ilgili bilgi toplayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.6.1.2', 7, 6, 'ELEKTRİKLENME', 'Elektriklenme çeşitlerini belirlemeye yönelik deney yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.6.1.3', 7, 6, 'ELEKTRİKLENME', 'Cisimlerin elektrik yüklerini sınıflandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.7.7.1.1', 7, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE ENERJİ', 'Besin zincirindeki canlıları arasındaki ilişkileri yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
