  (fb_id, 'FB.8.1.1.1', 8, 1, 'GÖKYÜZÜNDEKİ', 'Dünya''nın Güneş etrafındaki hareketi ve eksen eğikliğinin sonuçları ile ilgili bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
