  (fb_id, 'FB.8.3.1.1', 8, 3, 'YAŞAMIN GİZEMİ', 'Nükleotid, gen, DNA ve kromozom kavramları arasındaki ilişkiyi yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.3.1.2', 8, 3, 'YAŞAMIN GİZEMİ', 'DNA''nın yapısını model üzerinde gözlemleyebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.3.2.1', 8, 3, 'YAŞAMIN GİZEMİ', 'Mitoz ve mayoz kavramları arasındaki ilişkiyi karşılaştırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.3.3.1', 8, 3, 'YAŞAMIN GİZEMİ', 'Kalıtımla ilgili kavramları yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.3.3.2', 8, 3, 'YAŞAMIN GİZEMİ', 'Tek karakter çaprazlamaları ile ilgili problemler çözerek sonuçları değerlendirebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
