  (fb_id, 'FB.8.3.4.1', 8, 3, 'YAŞAMIN GİZEMİ', 'Mutasyonla ilgili bilgi toplayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.3.4.2', 8, 3, 'YAŞAMIN GİZEMİ', 'Canlıların yaşadıkları çevreye uyumlarına ilişkin bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.1.1', 8, 4, 'SESİN DÜNYASI', 'Öğrencilerin istedikleri bir müzik aletini sınıf ortamına getirmeleri istenebilir. Çeşitli mü zik aletlerini (saz, davul, flüt vb.) kullanarak sesin oluşumuna yönelik gözlem yapmaları sağlanır (SDB1.2, E2.5). Sınıf veya laboratuvar ortamında olabildiğince sessiz bir ortam', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.1.2', 8, 4, 'SESİN DÜNYASI', 'Sesin yayılabildiği ortamlara yönelik deney yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.1.3', 8, 4, 'SESİN DÜNYASI', 'Sesin frekansına göre ince veya kalın olarak işitilmesine neden olan ses özellikleri ile ilgili deney yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.2.1', 8, 4, 'SESİN DÜNYASI', 'Ders öncesinde, ses kaynağından uzaklığın ve ses şiddetinin işitmeye etkisi ile ilgili bir se naryo veya problem durumu öğretmen tarafından hazırlanır. Öğrencilerden bu senaryoda verilen problemi tanımlamaları istenir (SDB3.3). Tanımladıkları problemde ses kaynağın', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.2.2', 8, 4, 'SESİN DÜNYASI', 'Farklı maddeler ile etkileşimi sonucunda sesin iletilmesi, yansıması ve soğurulmasına ilişkin bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.4.2.3', 8, 4, 'SESİN DÜNYASI', 'Ses kirliliğini önlemeye yönelik bilimsel sorgulama yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.1.1', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Elementleri periyodik tablo üzerinde metal, ametal, yarımetal ve soy gaz olarak sınıflandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.2.1', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Fiziksel ve kimyasal değişimler ile ilgili bilimsel gözleme dayalı tahmin edebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.3.1', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Kimyasal tepkimelerle ilgili bilimsel çıkarım yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.3.2', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Kimyasal tepkimelerin günlük yaşamdaki etkilerine yönelik bilgi toplayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.4.1', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Asit ve bazlar konusu ile ilgili kavram yanılgıları iki aşamalı teşhis testleri gibi teknikler kullanılarak belirlenebilir. Öğrencilere iyon konusu ile ilgili açık uçlu sorular sorularak asit ve bazların sulu çözeltilerine verdikleri iyonlar belirtilir. Asit ve bazların temizlik', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.4.2', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Sınıfa saf su, sabun, limon suyu, sirke, deterjan, şampuan, yoğurt, süt, çamaşır suyu vb. malzemeler getirilir. Öğrenciler gruplara ayrılarak gerekli uyarılar yapılır ve öğrencilerin güvenlik önlemleri almaları sağlanır (D3.4, SDB2.2). Her gruptan aynı malzemelerden', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.4.3', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Öğrencilere günlük yaşamda karşılaşılan asitlik değeri farklı malzemelerden örnekler verilerek gösterdikleri asitlik-bazlık derecesinin birbirinden farklı olabileceğine yönelik açık uçlu sorular sorulabilir. pH cetveli ile maddelerin asitlik-bazlık derecesinin', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.5.4.4', 8, 5, 'PERİYODİK TABLO VE MADDENİN ETKİLEŞİMİ', 'Asit ve bazların çeşitli maddeler üzerindeki etkilerine yönelik deney yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.1.1', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Ampullerin bağlanma durumunun ampul parlaklığına etkisine yönelik deney yapabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.1.2', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik akımını tanımlayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.1.3', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Bir devre elemanının uçları arasındaki potansiyel farkı (gerilimi) tanımlayabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.1.4', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Bir devre elemanının uçları arasındaki gerilim ile üzerinden geçen akım ilişkisine yönelik tümevarımsal akıl yürütebilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.1.5', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Özgün bir aydınlatma aracı modeli oluşturabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.2.1', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik enerjisinin dönüştüğü enerjileri sınıflandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.2.2', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik enerjisinin ısı, ışık, ses veya hareket enerjisine dönüşümüne yönelik bir model oluşturabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.2.3', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik enerjisi üretim santrallerini sınıflandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.2.4', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik enerjisi üretim santrallerinin avantaj ve dezavantajlarını tartışabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.6.2.5', 8, 6, 'ELEKTRİĞİN YOLCULUĞU', 'Elektrik enerjisinin bilinçli ve tasarruflu kullanılmasının önemini tartışabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.1.1', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Bitkilerde besin üretiminde fotosentezin önemini yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.1.2', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Fotosentez hızını etkileyen faktörler ile ilgili hipotez oluşturabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.1.3', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Canlılarda solunumun önemini yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.2.1', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Öğrencilerin madde döngülerinin önemi ile ilgili tartışmaları sağlanabilir. Tartışma sırasında Türkçe dersinde yer alan iletişim becerilerinden faydalanılabilir. Su, oksijen ve karbon döngülerinin şemalarını gösteren model, poster, video, animasyon vb. ile öğrencilerin', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.2.2', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Madde döngülerinin yaşam açısından önemini yapılandırabilme', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.2.3', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Küresel iklim değişikliğinin nedenlerini ve olası sonuçlarını içeren örnek olay senaryosu üzerinden beyin fırtınası tekniği yaptırılabilir. Küresel iklim değişikliğinin olası sonuçlarının insan ve çevre üzerindeki etkileri konusunda öğrencilerin dijital, basılı ve görsel kaynaklar', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu'),
  (fb_id, 'FB.8.7.2.4', 8, 7, 'SÜRDÜRÜLEBİLİR YAŞAM VE MADDE DÖNGÜLERİ', 'Öğrencilere ülkemizdeki küresel iklim değişikliğinin sebep olduğu çevre sorunlarını konu alan görsel, haber, belgesel vb. sunularak çevre sorunlarına vurgu yapılır. Öğrencilerin çevre sorunları ile ilgili merak ettikleri soruları sormaları istenir (E3.8). Dijital, yazılı ve', NULL, 'Fen Bilimleri', 'ortaokul', 'zorunlu');
